import { useState } from "react"
import API from "../services/api"

export default function Jobs() {

    const [skills, setSkills] = useState("")
    const [qualification, setQualification] = useState("")
    const [experienceLevel, setExperienceLevel] = useState("Entry")

    const [result, setResult] = useState(null)

    const qualifications = [

        "Bachelor's in Computer Science",
        "Bachelor's in Cybersecurity",
        "Bachelor's in Design",
        "Bachelor's in Game Development",
        "Bachelor's in Graphic Design",
        "Bachelor's in Information Technology",
        "Bachelor's in Marketing",
        "Bachelor's in Software Engineering",
        "Bachelor's in Statistics",

        "Master's in Business Administration",
        "Master's in Computer Science",
        "Master's in Cybersecurity",
        "Master's in Data Science",
        "Master's in Finance",
        "Master's in Human Resources",
        "Master's in Software Engineering",

        "PhD in Artificial Intelligence"
    ]

    const handlePredict = async () => {

        try {

            const token =
                localStorage.getItem("token")

            await API.put(
                "/profile/update",
                {
                    skills: skills
                        .split(",")
                        .map(s => s.trim()),

                    qualification,

                    experienceLevel
                },
                {
                    headers: {
                        Authorization:
                            `Bearer ${token}`
                    }
                }
            )

            const response = await API.post(
                "/jobs/recommend",
                {
                    headers: {
                        Authorization:
                            `Bearer ${token}`
                    }
                }
            )

            setResult(response.data)

        } catch (error) {

            console.log(error)

            alert("Prediction failed")
        }
    }

    return (

        <div
            style={{
                maxWidth: "800px",
                margin: "40px auto",
                padding: "30px",
                background: "#fff",
                borderRadius: "15px",
                boxShadow:
                    "0 4px 15px rgba(0,0,0,0.1)"
            }}
        >

            <h1
                style={{
                    textAlign: "center",
                    marginBottom: "30px"
                }}
            >
                AI Career Predictor
            </h1>

            <label>
                Skills
            </label>

            <textarea
                rows="4"
                placeholder="Example: Python, SQL, Machine Learning, React"
                value={skills}
                onChange={(e) =>
                    setSkills(e.target.value)
                }

                style={{
                    width: "100%",
                    padding: "12px",
                    marginTop: "8px",
                    marginBottom: "20px"
                }}
            />

            <label>
                Qualification
            </label>

            <select
                value={qualification}
                onChange={(e) =>
                    setQualification(
                        e.target.value
                    )
                }

                style={{
                    width: "100%",
                    padding: "12px",
                    marginTop: "8px",
                    marginBottom: "20px"
                }}
            >

                <option value="">
                    Select Qualification
                </option>

                {
                    qualifications.map((q, i) => (

                        <option
                            key={i}
                            value={q}
                        >
                            {q}
                        </option>

                    ))
                }

            </select>

            <label>
                Experience Level
            </label>

            <select
                value={experienceLevel}
                onChange={(e) =>
                    setExperienceLevel(
                        e.target.value
                    )
                }

                style={{
                    width: "100%",
                    padding: "12px",
                    marginTop: "8px",
                    marginBottom: "25px"
                }}
            >

                <option value="Entry">
                    Entry
                </option>

                <option value="Mid">
                    Mid
                </option>

                <option value="Senior">
                    Senior
                </option>

            </select>

            <button
                onClick={handlePredict}
                style={{
                    width: "100%",
                    padding: "14px",
                    border: "none",
                    background: "#4CAF50",
                    color: "white",
                    fontSize: "16px",
                    borderRadius: "8px",
                    cursor: "pointer"
                }}
            >
                Predict Career Role
            </button>

            {

                result && (

                    <div
                        style={{
                            marginTop: "35px"
                        }}
                    >

                        <h2>
                            Predicted Role:
                        </h2>

                        <h1
                            style={{
                                color: "#4CAF50"
                            }}
                        >
                            {result.recommendedRole}
                        </h1>

                        <h3>
                            Match Score:
                            {" "}
                            {result.matchScore}%
                        </h3>

                        <hr />

                        <h2>
                            Top Career Matches
                        </h2>

                        {

                            result.topPredictions?.map(
                                (
                                    item,
                                    index
                                ) => (

                                    <div
                                        key={index}
                                        style={{
                                            marginBottom:
                                                "20px"
                                        }}
                                    >

                                        <strong>
                                            {item.role}
                                        </strong>

                                        <div
                                            style={{
                                                background:
                                                    "#ddd",
                                                height:
                                                    "20px",
                                                borderRadius:
                                                    "10px",
                                                overflow:
                                                    "hidden",
                                                marginTop:
                                                    "5px"
                                            }}
                                        >

                                            <div
                                                style={{
                                                    width:
                                                        `${item.match_score}%`,
                                                    background:
                                                        "#4CAF50",
                                                    height:
                                                        "100%"
                                                }}
                                            />

                                        </div>

                                        <p>
                                            {
                                                item.match_score
                                            }
                                            %
                                        </p>

                                    </div>

                                )
                            )
                        }

                    </div>

                )

            }

        </div>
    )
}
